/**
 * Clamps an angle in radians to the range [0, 2π).
 * @param angle The angle in radians to clamp.
 * @returns The clamped angle in radians.
 */
export function clampAngle(angle: number): number {
    const clampedAngle = angle % (2 * Math.PI);
    if (clampedAngle < 0) {
        return clampedAngle + 2 * Math.PI;
    }
    return clampedAngle;
}
